import React from 'react';

const posts = [
  { id: 1, title: 'First Post', excerpt: 'Welcome to my migrated React blog!', date: 'Mar 5, 2026' },
  { id: 2, title: 'React Tips', excerpt: 'useState is a powerful hook.', date: 'Mar 4, 2026' }
];

function HomePage() {
  return (
    <div className="container">
      <h1>Latest Posts</h1>
      <div className="posts-grid">
        {posts.map(post => (
          <div key={post.id} className="post-card"> {/* [cite: 276] */}
            <h2>{post.title}</h2>
            <p>{post.excerpt}</p>
            <span>{post.date}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default HomePage;
